@implements IAsyncDisposable
@inject IJSRuntime JS

@ChildContent

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private IJSObjectReference? _jsModule;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;
    private System.Timers.Timer? _timer;
    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        _dotNetRef = DotNetObjectReference.Create(this);
        _jsModule = await JS.InvokeAsync<IJSObjectReference>(
            "import", "./_content/sv-cf3bc5ef7166463bb6fe31660f923de4/Components/UserActivityTracker.razor.js"
        );

        _timer = new System.Timers.Timer(TimeoutSeconds * 1000);
        _timer.AutoReset = false;
        _timer.Elapsed += OnTimerElapsed;
        _timer.Start();

        await _jsModule.InvokeVoidAsync("register", _dotNetRef);
    }

    [JSInvokable]
    public async Task OnUserActivity()
    {
        _timer?.Stop();
        _timer?.Start();

        if (_isIdle)
        {
            _isIdle = false;
            await InvokeAsync(OnActive.InvokeAsync);
        }
    }

    private async void OnTimerElapsed(object? sender, System.Timers.ElapsedEventArgs e)
    {
        if (!_isIdle)
        {
            _isIdle = true;
            await InvokeAsync(OnIdle.InvokeAsync);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_timer is not null)
        {
            _timer.Elapsed -= OnTimerElapsed;
            _timer.Stop();
            _timer.Dispose();
            _timer = null;
        }

        if (_jsModule is not null)
        {
            try
            {
                await _jsModule.InvokeVoidAsync("unregister");
                await _jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
            _jsModule = null;
        }

        _dotNetRef?.Dispose();
        _dotNetRef = null;
    }
}

let _dotNetRef = null;
let _handler = null;

export function register(dotNetRef) {
    _dotNetRef = dotNetRef;

    _handler = () => {
        _dotNetRef.invokeMethodAsync("OnUserActivity");
    };

    const events = ["mousemove", "keydown", "click", "scroll"];
    for (const evt of events) {
        document.addEventListener(evt, _handler, { passive: true });
    }
}

export function unregister() {
    if (_handler) {
        const events = ["mousemove", "keydown", "click", "scroll"];
        for (const evt of events) {
            document.removeEventListener(evt, _handler);
        }
        _handler = null;
    }
    _dotNetRef = null;
}

